#!/bin/bash\n\n# Script to rename image files to remove double extensions\nfor file in *; do\n    if [[ -f "$file" ]]; then\n        # Remove double '.jpg.jpg' to '.jpg'\n        if [[ "$file" == *.jpg.jpg ]]; then\n            mv "$file" "${file%.jpg.jpg}.jpg"\n        fi\n        # Remove double '.jpg.jpeg' to '.jpeg'\n        if [[ "$file" == *.jpg.jpeg ]]; then\n            mv "$file" "${file%.jpg.jpeg}.jpeg"\n        fi\n    fi\ndone\n